#include <stdio.h>
#include <stdlib.h>
#include <inttypes.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long *arr = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &arr[i]);
        int M; scanf("%d", &M);
        long long *dp = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) dp[i] = 0;
        for (int i = 0; i < N; ++i) {
            long long maxVal = 0;
            for (int j = 1; j <= M && i - j + 1 >= 0; ++j) {
                if (arr[i - j + 1] > maxVal) maxVal = arr[i - j + 1];
                long long cand = maxVal * j;
                if (i - j >= 0) cand += dp[i - j];
                if (cand > dp[i]) dp[i] = cand;
            }
        }
        printf("%" PRId64 "\n", dp[N-1]);
        free(arr);
        free(dp);
    }
    return 0;
}

